# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.

Prevent race conditions.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketBookingService
{
    private readonly EventContext _context;

    public TicketBookingService(EventContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        // Check if the event exists and has available seats
        var @event = await _context.Events.FindAsync(eventId);
        if (@event == null || @event.AvailableSeats < quantity)
        {
            return false;
        }

        // Validate the purchase quantity
        if (quantity <= 0 || quantity > @event.MaximumPurchaseQuantity)
        {
            return false;
        }

        // Update inventory and commit changes to database
        @event.AvailableSeats -= quantity;
        await _context.SaveChangesAsync();

        return true;
    }
}